sp_widget.client_script:
function dtlvCtrl($scope, spModal, $rootScope, spUtil, $timeout) {
    var c = this;
	  // set value on client load instead of in server
		c.data.isPrint = false;

    // STRY0088168 - DTLV has a scroll bar that does not allow printing to be displayed correctly
    $scope.printReport = function() {
        var originalContents = document.body.innerHTML;
        var printReport = document.getElementById('printDiv').innerHTML;
        document.body.innerHTML = printReport;
        window.print();
        // window.print()
        window.location.reload();
        //document.body.innerHTML = originalContents;
    };

    // 2.6.0 | 2021-03-11 | mmcc | STRY0092273 DTLV – Optimize Print of the Dynamic Tree Level View
    $scope.printPreviewToggle = function() {

        c.data.isPrint = !c.data.isPrint;
			// reload on toggle.  NOTE: currently it is not reloading.  There is a javascript error somewhere on reload.
			// DFCT0011169

			if(c.data.isPrint && c.data.subTasksRequestsPrints.length==0){
				$scope.data.getPrintData = true;
					spUtil.update($scope);
			}

			_loadDynamicDocIntWidgets();			
    };

    $scope.previewPrint = function() {

        window.print();
    };

		// DFCT0011169
		_loadDynamicDocIntWidgets();

		// DFCT0011169
		function _loadDynamicDocIntWidgets() {
			if(c.data.DocIntON && 
				 $scope.data._dtlv_docint_widget_container){
				for (var i in $scope.data._dtlv_docint_widget_container._docint_tabs) {
					var _tab = $scope.data._dtlv_docint_widget_container._docint_tabs[i];
					_loadDocIntWidget($scope.data._dtlv_docint_widget_container._docint_tabs[i]);
				}
			}
		}

		// DFCT0011169
		function _loadDocIntWidget(_docFolder){
			_docFolder.widget=null;
			var widget_name = _docFolder.widget_name;
			var widget_parameters = _docFolder.widgetParameter;
			if(widget_name == 'docint-list-items') {
				if(c.data.isPrint){
					c.data.docInt_print_loaded=true;
					widget_parameters = {
						vw: _docFolder.config["docintegrator_view-refValue"],
						mapRowSysId: c.data.sys_id + "",
						// deprecated readonly_flag
						// readonly_flag: !c.data.isActive,
						// DFCT0012044 - had this backward
						read_only: true,
						lw_name: _docFolder.id + _docFolder.caption,
						window_size: c.data.rowSize,
						config_sys_id: _docFolder.id,
						// STRY0115311
						siblings : _docFolder.siblings,
						color: 'primary'
					};				
				} else {
					c.data.docInt_view_loaded=true;
					widget_parameters = {
						vw: _docFolder.config["docintegrator_view-refValue"],
						mapRowSysId: c.data.sys_id + "",
						// deprecated readonly_flag
						// DFCT0012044 - had this backward
						read_only: !c.data.isActive,
						lw_name: _docFolder.id + _docFolder.caption,
						config_sys_id: _docFolder.id,
						// STRY0115311
						siblings : _docFolder.siblings,
						color: 'primary'
					};
				}
			}
			// STRY0111049 - moved outside the IF statement and also set to use widgetname 
			spUtil.get(widget_name, widget_parameters).then(function(response) {
				_docFolder.widget = response;
			});

		}	
}

