/*------------------------------------------------------------------------------------------------------------------------*/
/*
NAME: DYNAMIC TREE LEVEL SUMMARY 
COMPANY: DISCOVER TECHNOLOGIES
CUSTOMIZED BY: KARINA TORRES
WIDGET BASE: N/A
*/
/*------------------------------------------------------------------------------------------------------------------------*/
/* 2.5.3 | 10.01.2020 | KT | UI  | STRY0059017: TLV –Stretch - Add a linked Table of Contents to the top of the Tree Level Object form */
/*------------------------------------------------------------------------------------------------------------------------*/


@media (min-width: 576px)
  .dtlv {
    padding: 1.5rem;
    margin-right: 0;
    margin-left: 0;
    border-width: .2rem;
}

.spybody {
  /* height: 500px; */
  overflow-y: scroll;
  /*padding: 10px; */
}

.nav {
  display: -ms-flexbox;
  display: flex;
  -ms-flex-wrap: wrap;
  flex-wrap: wrap;
  padding-left: 0;
  margin-bottom: 0;
  list-style: none;
}

.navbar {
  position: relative;
  display: -ms-flexbox;
  display: flex;
  -ms-flex-wrap: wrap;
  flex-wrap: wrap;
  -ms-flex-align: center;
  align-items: center;
  -ms-flex-pack: justify;
  justify-content: space-between;
  padding: .5rem 1rem;
}

.nav-pills .nav-link.active, .nav-pills .show>.nav-link {
  color: #fff;
  background-color: #007bff;
}

.nav-pills .nav-link {
  border-radius: .25rem;
}

.nav-link {
  display: block;
  padding: .5rem 1rem;
}

/*------------------------------------------------------------------------------------------------------------------------*/
/* 2.5.21 | 09.02.2020 | KT | UI  | STRY0074067: TECH - Tasker - Unified CSS on widgets (Internal Story, PO story needed) */
/*------------------------------------------------------------------------------------------------------------------------*/

.glyphicon {
  margin-right: 10px !important;
}

.panel-heading {
  font-size: 16px !important;
}

.content {
  margin-left: 15px !important;
  margin-right: 20px !important;
}

