// Copyrights belong to Discover Technologies LLC. © 2021 Discover Technologies LLC
// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// CREATED BY: KARINA TORRES
// WIDGET BASE: N/A.
//------------------------------------------------------------------------------------------------------------------------
//
// 2.6.0 | 2021-03-11 | mmcc | STRY0092273 DTLV – Optimize Print of the Dynamic Tree Level View
// 2.6.0 | 2021-03-12 | mmcc | STRY0095573 Remove Response Column from DTLV Sub Task List View
// 2.6.0 | 2021-03-18 | raj  | STRY0095956 - Tree Level Print Report:  Navigation- Return to DTLV, corrected spelling and made all text multilingual in HTML
// 2.6.0 | 2021-03-25 | mmcc | STRY0096103 Tree Level Print Report: Activity Log
// 2.6.0 | 2021-04-27 | raj  | STRY0100645 GlideRecord functions do not enforce ACLs. Please use GlideRecordSecure wherever possible to enforce ACLs
// 2.7.0 | 2021-06-29 | mmcc | STRY0104015 DTLV - HTML fields are being trimmed to 4000 characters (General Objective Field and the Instructions fields)
//											Replaced calls to .getHTMLValue(4000) to be .getHTMLValue() for objective and instructions
//											HTML to use new selector in Page Dynamic Task Tree; CSS updated to use standard CSS comment /* */
//											Changes in HTML, CSS and Server script
// 2.7.0 | 2021-08-05 | raj | STRY0105031 DIA: "Objective" field update does not pass from "Top Task" to all children tasks
//											Changes in Server Script Only
// 2.7.0 | 2021-11-16 | raj  | STRY0113838 - Tasker Settings- Allow for custom "URL Suffix" for Tasker Portal
//                                         Changes made in Server Script and HTML
// 2.7.0 | 2021-11-18 | raj  | STRY0114416 - 4 - 2.7 Certification Fixes
//                                         Changes made in Server Script
// 2.7.1 | 2021-12-17 | raj  | DFCT0010593 - DIA: "Tasker Number" and "Task Name" fields are blank on "Excel Export" from DTLV
//                                         Changes made in Server Script
// 2.7.1 | 2021-12-17 | raj  | DTLV - add views for all lists in the report to allow customers to customize the list of fields
//                                         Changes made in Server Script
// 2.7.3 | 2022-05-03 | raj  | DFCT0010773 - DTLV - add print view for DocIntegrator
//                                         Changes made in Server Script and HTML
// 2.8.0 | 2022-08-22 | raj  |  DFCT0010862 - DTLV page is displaying, "Go to Task Details Page to edit Task" button 
//																					Changes in HTML only, removed edit button
//
// 2.8.0 | 2022-08-24 | raj  | DFCT0011211 - DTLV page should NOT display white color widgets for the "On Time", "Warning" & "Critical" under the Subtasks by Status section header
//                                         Changes made in Server Script, Client Controller and HTML
// 2.8.0 | 2022-08-24 | raj  | DFCT0011169 - Stretch: Empty data displays under "Activity Log" modal
//                                         Changes made in Server Script, Client Controller and HTML
// 2.8.0 | 2022-08-24 | raj  DFCT0011379 - On the "DTLV View" page "Subtasks by State" graphic is only counting direct subs and NOT down the tree
//                                         Changes in the Server Script
// 2.8.3 | 2023-05-30 | raj  | DFCT0010631 - Activity Log in DTLV does NOT display some columns for Tasker Users - Only Platform Admin can see
//																			Changes in Server Script Only
// 2.8.3 | 2023-07-03 | raj  | DFCT0012044 - Upload icon is missing from Tasker DTLV Shared Documents. Also, users cannot drag or drop files onto the widget. 
//																			Changes in Client Controller and Server Script
// 
//------------------------------------------------------------------------------------------------------------------------

(function($sp, input, data, options, gs) {
    /* populate the 'data' object */
    /* e.g., data.table = $sp.getValue('table'); */
		// DFCT0011211
		var OOTB_COUNT_WIDGET_ID = "tasker_simple_count";

    data.sys_id = $sp.getParameter("sys_id");
    data.table = $sp.getParameter("table");
    data.view = 'sp';

	data.getPrintData = input && input.getPrintData==true; 

		// STRY0113838
		var oUserPref = new tasker_User_Form_Preferences();
		var url_Properties = oUserPref.get_URL_Properties_for_Task_Based_on_Prefrences(data.sys_id, data.view);

		data.task_url =  
			'../' + url_Properties.portal_url_ref + 
			'?id=' + url_Properties.pageId + 
			'&table=' + data.table + 
			'&sys_id=' + data.sys_id +
			'&view=' + url_Properties.view;


    // mmcc STRY0092273 - Default row size or Admin settable value
    data.defaultRowSize = 20;
    data.rowSize = gs.getProperty('x_153465_discovert.DynamicTreeLevelRowsPerPagePrint');

	// STRY0114416 - 4
    // STRY0100645
    var gr_DTLV = new GlideRecordSecure('x_153465_discovert_route_task_instance');
    if (gr_DTLV.get(data.sys_id)) data.task_tree_sys_id = gr_DTLV.u_task_tree.sys_id.toString();


    //------------------------------------------------------------------------------------------------------------------------
    //  DOC. INT INTEGRATION - INITIALIZING VARIABLES 
    //------------------------------------------------------------------------------------------------------------------------
    var tDS = new taskerDocumentScripts();
    var currentAttachDocSettings = tDS.getAttachmentAndDocumentSettings(gr_DTLV);
    data.SNAttachmentsON = currentAttachDocSettings.sNOWAttachmentsOn;
    data.DocIntON = currentAttachDocSettings.docIntDocumentsOn;

    //------------------------------------------------------------------------------------------------------------------------
    // Box 1:  Objective | Instructions
    //------------------------------------------------------------------------------------------------------------------------
    data.task_name = gr_DTLV.task_name.toString();
    data.calchaschildren = gr_DTLV.calchaschildren.toString();

    // mmcc STRY0092273 Removed regex that was striping the HTML tags and now let ng-bind-html show the styled web page
    // data.objective = gr_DTLV.u_objective.getHTMLValue(4000).replace(/<\/?[^>]+(>|$)/g, "") + "" + gr_DTLV.u_objective_sub_task.getHTMLValue(4000).replace(/<\/?[^>]+(>|$)/g, "");
    // 2.7.0 | 2021-06-29 | mmcc | STRY0104015 DTLV - HTML fields are being trimmed
    // data.objective = gr_DTLV.u_objective.getHTMLValue(4000) + "" + gr_DTLV.u_objective_sub_task.getHTMLValue(4000);
    // //data.instructions = gr_DTLV.instructions.getHTMLValue(4000).replace(/<\/?[^>]+(>|$)/g, ""); //gr_DTLV.instructions.toString();
    // data.instructions = gr_DTLV.instructions.getHTMLValue(4000);
		// STRY0105031
		data.objective = gr_DTLV.u_top_task.u_objective.getHTMLValue();
    data.instructions = gr_DTLV.instructions.getHTMLValue();
		// DFCT0012044 - set active flag
		data.isActive = gr_DTLV.active;
    //------------------------------------------------------------------------------------------------------------------------
    // Box 10: Task Tree Graph
    //------------------------------------------------------------------------------------------------------------------------

    // mmcc STRY0092273 commented out to getwidget() as not used in HTML
    //     var tasktreeGraph_Options = {
    //         table: data.table,
    //         sys_id: data.sys_id
    //     };

    //     data.tasktreeGraph = $sp.getWidget('discovertasker-recursivetasktreegraph', tasktreeGraph_Options);


    //------------------------------------------------------------------------------------------------------------------------
    // Box 3: Summary Card
    //------------------------------------------------------------------------------------------------------------------------

    var summarycard_Options = {
        table: data.table,
        title: 'Summary Card',
        show_systemfields: true,
        filter: 'taskernumber,number,suspense_date,classification,tasking_authority,primary_assignee,short_description,state,status,tasker_type,u_reviewer,u_task_requester,primary_assignee,assigned_to'
    };

    data.summarycard = $sp.getWidget('discovertasker-summarycard', summarycard_Options);


    //------------------------------------------------------------------------------------------------------------------------
    // Box 3: Sub Tasks
    //------------------------------------------------------------------------------------------------------------------------
    var filter = 'u_task_tree=' + data.task_tree_sys_id + '^u_all_ancestors_tasksLIKE' + data.sys_id;
    var o = "number";
    var d = "asc";
	data.subTasksPrints = [];
	if(!data.getPrintData){
		// STRY0115991
		var subTasks_Options = {
				title: 'Subtasks',
				table: data.table,
				filter: filter,

				enable_filter: false,
				show_keywords: false,
				show_breadcrumbs: false,
				// STRY0115991
				view: 'DTLV_SubTasks',
				platform_view: 'pfm_DTLV_Subtasks',
				// mmcc STRY0095573 - Removed heading Response Comments by dropping response from fields
				//fields: 'parent,taskernumber,number,tasker_type,short_description,calchaschildren,classification,state,status,suspense_date,primary_assignee,assigned_to,provide_response,decision,response', //,comments_and_work_notes',
				//fields: 'parent,taskernumber,number,tasker_type,short_description,calchaschildren,classification,state,status,suspense_date,primary_assignee,assigned_to,provide_response,decision', //response', //,comments_and_work_notes',

				// mmcc STRY0092273 - Default row size or Admin settable value
				window_size: data.defaultRowSize,

				display_field: 'number',
				glyph: 'pencil-square-o', //bell-slash-o',
				open_row_details_in_modal: true,
				o: o,
				d: d,
				color: 'primary'
		};

		data.subTasks = $sp.getWidget('discovertasker-widget-data-table', subTasks_Options); //widget-data-table //discovertasker-widget-data-table
	} else {
		var stp={};
		// mmcc STRY0092273 - Created Print options for subTasks
		var subTasksPrint_Options = {
				title: 'Subtasks',
				table: data.table,
				filter: filter,

				enable_filter: false,
