		};
		// mmcc STRY0092273 - Created widget using Print options for Response Log
		srlp.widget = $sp.getWidget('discovertasker-widget-data-table', responseLogPrint_Options);
		data.subResponseLogPrints.push(srlp);
	}

    //------------------------------------------------------------------------------------------------------------------------
    // Box 4: Request Log
    //------------------------------------------------------------------------------------------------------------------------
    data.table_request = 'x_153465_discovert_tasker_requests';
    var filter_request = 'parent.u_task_tree=' + data.task_tree_sys_id + '^parent.u_all_ancestors_tasksLIKE' + data.sys_id;

    var o_request = "parent";
    var d_request = "asc";
	data.subTasksRequestsPrints=[];

	if(!data.getPrintData){
		var subTasksRequests_Options = {
				title: 'Requests',
				table: data.table_request,
				filter: filter_request,

				enable_filter: false,
				show_keywords: false,
