		};

		data.subTasksRequests = $sp.getWidget('discovertasker-widget-data-table', subTasksRequests_Options); //widget-data-table //discovertasker-widget-data-table
	} else {
		var strp = {};
		// mmcc STRY0092273 - Created Print options for Requests
		var subTasksRequestsPrint_Options = {
				title: 'Requests',
				table: data.table_request,
				filter: filter_request,

				enable_filter: false,
				show_keywords: false,
				show_breadcrumbs: false,

				//Parent Task,Tasker Number, Number,Task Name, Request Number, Request Type
				// STRY0115991
				view: 'DTLV_Print_Requests',
				platform_view: 'pfm_DTLV_Print_Requests',			

				// mmcc STRY0092273 - Reduced which columns are used in printing but added Task Number & Name
				//fields: 'parent.taskernumber,parent.number,parent.short_description,number,u_request_type,u_request_comments,u_requested_by,u_requested,u_status,u_response,u_response_comments,u_responded_by,u_responded',
				//fields: 'parent.task_name,parent.number,u_request_type,u_requested_by,u_requested,u_status,u_responded_by,u_responded',

				// mmcc STRY0092273 - Default row size or Admin settable value
				window_size: data.rowSize,

				//display_field: 'number',
				glyph: 'bullhorn',
				open_row_details_in_modal: true,
				o: o_request,
				d: d_request,
				color: 'primary'
		};

		// mmcc STRY0092273 - Created widget using Print options for Requests
		strp.widget = $sp.getWidget('discovertasker-widget-data-table', subTasksRequestsPrint_Options);
		data.subTasksRequestsPrints.push(strp);
	}

    //------------------------------------------------------------------------------------------------------------------------
    // Box 4: Activity Log
    //------------------------------------------------------------------------------------------------------------------------
    data.table_audit = 'x_153465_discovert_activity_view';
    var filter_audit = 'taskid_u_task_tree=' + data.task_tree_sys_id + '^taskid_u_all_ancestors_tasksLIKE' + data.sys_id;
    //filter_audit = 'taskid_u_all_ancestors_tasksLIKE'+ data.sys_id+'^journalid_valueNOT LIKERequest has been';

    var o_audit = "taskid_number";
    var d_audit = "asc";
	data.subTasksActivityPrints=[];

	if(!data.getPrintData){
		var subTasksActivity_Options = {
				title: 'Activity Log',
				// DFCT0010631 - data table needs task id in order to check security and display some of the fields
				task_id: data.sys_id,
				table: data.table_audit,
				filter: filter_audit,

				enable_filter: false,
				show_keywords: false,
				show_breadcrumbs: false,

				view: 'dtlv_activity_log',
				platform_view: 'pfm_dtlv_activity_log',			

				//fields: 'taskid_parent,taskid_taskernumber,taskid_number,taskid_short_description,journalid_sys_created_by,journalid_sys_created_on,journalid_element,journalid_value',

				// mmcc STRY0092273 - Default row size or Admin settable value
				window_size: data.defaultRowSize,

				//display_field: 'number',
				glyph: 'comment-o',
				open_row_details_in_modal: false,
				o: o_audit,
				d: d_audit,
				color: 'primary'
		};

		data.subTasksActivity = $sp.getWidget('discovertasker-widget-data-table', subTasksActivity_Options); //widget-data-table //discovertasker-widget-data-table
	} else {
		var stap = {};
		// mmcc STRY0092273 - Created Print options for Activity Log
		var subTasksActivityPrint_Options = {
				title: 'Activity Log',
				// DFCT0010631 - data table needs task id in order to check security and display some of the fields
				task_id: data.sys_id,
				table: data.table_audit,
				filter: filter_audit,

				enable_filter: false,
				show_keywords: false,
				show_breadcrumbs: false,

				view: 'dtlv_print_activity_log',
				platform_view: 'pfm_dtlv_print_activity_log',			

				//fields: 'taskid_parent,taskid_taskernumber,taskid_number,taskid_short_description,journalid_sys_created_by,journalid_sys_created_on,journalid_element,journalid_value',

				// mmcc STRY0092273 - Default row size or Admin settable value
				window_size: data.rowSize,

				//display_field: 'number',
				glyph: 'comment-o',
				open_row_details_in_modal: false,
				o: o_audit,
				d: d_audit,
				color: 'primary'
		};

		// mmcc STRY0092273 - Created widget using Print options for Activity Log
		stap.widget = $sp.getWidget('discovertasker-widget-data-table', subTasksActivityPrint_Options);
		data.subTasksActivityPrints.push(stap);
	}

		//------------------------------------------------------------------------------------------------------------------------
    // Box 5: Key Data: Reports?
    //------------------------------------------------------------------------------------------------------------------------
    // DFCT0011379 - added showDexc to the properties
		var progressBar_Options = {
        table: data.table,
        sys_id: data.sys_id,
				showDesc: true

    };

    data.progressBar = $sp.getWidget('discovertasker-statesmultiplebar', progressBar_Options);

    var countStatusOnTime_Options = {
        title: 'On Time',
        table: data.table,
        filter: filter + '^status=Projected on time',
        color: 'success',
        glyph: 'bell-o'
    };

		// DFCT0011211 - use OOTB widget instead of Tasker count
	data.countStatusOnTime = $sp.getWidget(OOTB_COUNT_WIDGET_ID, countStatusOnTime_Options);


    var countStatusWarning_Options = {
        title: 'Warning',
        table: data.table,
        filter: filter + '^status=Warning',
        color: 'warning',
        glyph: 'calendar-o'
    };

		// DFCT0011211 - use OOTB widget instead of Tasker count
    data.countStatusWarning = $sp.getWidget(OOTB_COUNT_WIDGET_ID, countStatusWarning_Options);


    var countStatusCritical_Options = {
        title: 'Critical',
        table: data.table,
        filter: filter + '^status=Critical',
        color: 'danger',
        glyph: 'bell-slash-o'
    };

		// DFCT0011211 - use OOTB widget instead of Tasker count
    data.countStatusCritical = $sp.getWidget(OOTB_COUNT_WIDGET_ID, countStatusCritical_Options);

    //------------------------------------------------------------------------------------------------------------------------
    // Box 6: Shared Attachments
    //------------------------------------------------------------------------------------------------------------------------
    var sharedAttachTableName;
    var sharedAttachSys_ID;

    if (data.table == "x_153465_discovert_route_task_instance") {
        sharedAttachTableName = 'x_153465_discovert_task_tree';
        sharedAttachSys_ID = data.task_tree_sys_id;
    }

    var sharedAttachment_Options = {
        title: 'Shared Attachments',
        record_table: sharedAttachTableName,
        record_id: sharedAttachSys_ID,
        record_name: 'sharedAttachmentWidget'
    };

    data.sharedAttachment = $sp.getWidget('tasker_task_attachments', sharedAttachment_Options);

    //------------------------------------------------------------------------------------------------------------------------
    // Box 7: Shared Documents
    //------------------------------------------------------------------------------------------------------------------------
		if (data.DocIntON) {
			if (data.isActive == "true" || data.isActive == true) data.isActive = true;
			else data.isActive = false;
			var docInt_table = "x_153465_discovert_route_task_instance";
			var docInt_view = "DTLView";
			data._dtlv_docint_widget_container = new x_dtll2_contentint.SFWHelper().getWidgetFormConfigurationTabs(docInt_table, docInt_view, data.sys_id);
		}

    // DFCT0012044 - this should not be hard coded
    // data.isActive = true;

})($sp, input, data, options, gs);
